func TestTronVectors(t *testing.T) {
	acc, err := NewAccountFromMnemonic(tronMnemonic, tronPath)
	if err != nil {
		t.Fatal(err)
	}
	if acc.Address() != tronSender {
		t.Fatalf("sender mismatch: got %s want %s", acc.Address(), tronSender)
	}

	for _, v := range tronVectors() {
		t.Run(v.name, func(t *testing.T) {
			b := NewTxBuilder(&Ingredient{
				TxType:            v.txType,
				ContractAddress:   v.contract,
				Sender:            tronSender,
				Recipient:         tronSender,
				Amount:            v.amount,
				Payload:           v.payload,
				FeeLimit:          "10000000",
				RefBlockHash:      tronRefHash,
				RefBlockNumber:    "12345",
				RefBlockTimestamp: "1700000000000",
			})
			if err := b.Build(); err != nil {
				t.Fatalf("build: %v", err)
			}
			if b.GetUnsignedHex() != v.unsigned {
				t.Fatalf("unsigned mismatch:\n got %s\nwant %s", b.GetUnsignedHex(), v.unsigned)
			}
			sig, err := b.Sign(acc.PrivateKey())
			if err != nil {
				t.Fatalf("sign: %v", err)
			}
			if sig != v.signature {
				t.Fatalf("signature mismatch:\n got %s\nwant %s", sig, v.signature)
			}
			signed, err := b.ConcatSignature(sig, false)
			if err != nil {
				t.Fatalf("concat: %v", err)
			}
			if signed != v.signed {
				t.Fatalf("signed mismatch:\n got %s\nwant %s", signed, v.signed)
			}
			if b.GetTxHash() != v.txHash {
				t.Fatalf("txHash mismatch: got %s want %s", b.GetTxHash(), v.txHash)
			}
		})
	}
}
